class Solution:
    def mostPoints(self, questions):
        # Independent forward formulation: dp[i] is the best score
        # obtainable by a strategy that is free to decide again exactly at
        # index i. Each question pushes its consequences forward (skip ->
        # i+1, solve -> past its cooldown) instead of pulling from the
        # future the way a backward scan does.
        n = len(questions)
        dp = [0] * (n + 1)
        for i in range(n):
            points, cooldown = questions[i]
            if dp[i] > dp[i + 1]:
                dp[i + 1] = dp[i]
            j = min(n, i + cooldown + 1)
            candidate = dp[i] + points
            if candidate > dp[j]:
                dp[j] = candidate
        return max(dp)

