class Solution:
    def mostPoints(self, questions):
        n = len(questions)
        dp = [0] * (n + 1)
        for i in range(n - 1, -1, -1):
            points, cooldown = questions[i]
            skip = dp[i + 1]
            solve = points + dp[min(n, i + cooldown + 1)]
            dp[i] = max(skip, solve)
        return dp[0]

