var mostPoints = function(questions) {
    const n = questions.length;
    const dp = new Array(n + 1).fill(0);
    for (let i = n - 1; i >= 0; i--) {
        const points = questions[i][0];
        const cooldown = questions[i][1];
        const skip = dp[i + 1];
        const nextIdx = Math.min(n, i + cooldown + 1);
        const solve = points + dp[nextIdx];
        dp[i] = Math.max(skip, solve);
    }
    return dp[0];
};
